const businessName = $('On form submission').first().json['Business Name'] ;

// Clean the business name for filename (remove spaces, special chars)
const cleanName = businessName.toLowerCase()
                              .replace(/[^a-z0-9]/g, '-')
                              .replace(/--+/g, '-')
                              .replace(/^-|-$/g, '');

// Create unique filename with timestamp
const timestamp = Date.now();
const fileName = `${cleanName}-${timestamp}.html`;

console.log('Generated filename:', fileName);

// Create a binary file with proper MIME type
return [{
  json: {
    html: htmlContent,
    fileName: fileName,  // Pass filename forward if needed
    businessName: businessName
  },
  binary: {
    data: {
      data: Buffer.from(htmlContent).toString('base64'),
      mimeType: 'text/html',
      fileName: fileName,
      fileExtension: 'html'
    }
  }
}];
